code = """import json
from collections import Counter, OrderedDict

# Read the patent data
file_path = locals()['var_functions.query_db:15']
with open(file_path, 'r') as f:
    patents_data = json.load(f)

# Filter for German patents granted in second half of 2019
filtered_patents = []
h2_2019_months = ['July', 'August', 'September', 'October', 'November', 'December']

for patent in patents_data:
    patents_info = patent.get('Patents_info', '')
    grant_date = patent.get('grant_date', '')
    
    if 'DE' in patents_info and '2019' in grant_date and any(month in grant_date for month in h2_2019_months):
        filtered_patents.append(patent)

cpc_level4_counts = Counter()
cpc_level4_info = {}

for patent in filtered_patents:
    cpc_field = patent.get('cpc', '[]')
    try:
        cpc_list = json.loads(cpc_field)
    except:
        continue
    
    for cpc_item in cpc_list:
        full_code = cpc_item.get('code', '')
        if not full_code:
            continue
        
        parts = full_code.split('/')
        if len(parts) >= 1:
            main_part = parts[0]
            # Extract level 4: first 5 characters (A61M1, C04B2, etc.)
            if len(main_part) >= 5:
                level4_code = main_part[:5]
                cpc_level4_counts[level4_code] += 1
                
                if level4_code not in cpc_level4_info:
                    cpc_level4_info[level4_code] = []
                cpc_level4_info[level4_code].append({
                    'full_code': full_code,
                    'patent_info': patent['Patents_info'],
                    'grant_date': patent['grant_date']
                })

# Get top 10 CPC codes
top_10_cpc = cpc_level4_counts.most_common(10)

# Create simplified result without truncating
cpc_list = []
for code, count in top_10_cpc:
    cpc_list.append({'code': code, 'count': count})

result = {
    'filtered_patents_count': len(filtered_patents),
    'unique_cpc_level4_count': len(cpc_level4_counts),
    'top_cpc_level4': cpc_list,
    'all_cpc_codes_sample': list(cpc_level4_counts.keys())[:50]
}

print('__RESULT__:')
print(json.dumps(result))"""

